INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('31294978-c3be-4e6f-b316-54a6a09db420', 'How long will abdominal pain last?', 'Mild abdominal pain may continue for 3–5 days and gradually decreases. Pain improving over time is normal.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'When can I resume normal diet?', 'You may start with soft foods on day 1–2 and return to a normal diet once your stomach feels comfortable. Avoid oily foods for a few days.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Can I sleep on my stomach?', 'Avoid sleeping on your stomach for at least 1 week. Sleeping on your back or side is recommended until pain reduces.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Is bloating normal after appendectomy?', 'Yes, mild bloating due to anesthesia or reduced bowel movement is common and improves within a few days.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'When can I remove the dressing?', 'Dressings can usually be removed after 48 hours unless your doctor has advised otherwise.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Can I climb stairs?', 'Yes, you may climb stairs slowly as long as you feel stable and comfortable.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'When will stitches dissolve?', 'Dissolvable stitches usually disappear within 10–14 days. If your stitches are non-dissolvable, your doctor will give a removal date.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'What foods should I avoid?', 'Avoid spicy, oily, or heavy meals for the first few days to prevent stomach discomfort.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Can I drive a vehicle?', 'Driving is usually possible after 5–7 days once pain reduces and you can move comfortably.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Why does my incision feel itchy?', 'Mild itching is a sign of healing. Avoid scratching the area to prevent infection.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'When can I return to office work?', 'Most people return to desk work within 5–7 days if pain is well controlled.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Can I lift my child?', 'Avoid lifting anything heavier than 4–5 kg for at least 2 weeks to prevent strain.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'When can I resume exercise?', 'Walking can start immediately. Light exercise in 1 week and full activity in 3–4 weeks with doctor approval.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'Is tiredness normal?', 'Yes, fatigue for a few days is common as your body recovers from surgery and anesthesia.'),
('31294978-c3be-4e6f-b316-54a6a09db420', 'When should I be concerned after appendectomy?', 'Seek help if pain worsens, fever develops, vomiting persists, or the incision becomes red or foul-smelling.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Why do I have shoulder pain?', 'Shoulder pain is caused by gas used during laparoscopic surgery. It usually resolves within 24–48 hours.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'When can I eat spicy foods?', 'Avoid spicy or fried foods for at least 1 week. Gradually reintroduce them depending on your digestion.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Is diarrhea normal after gallbladder removal?', 'Yes. Some patients experience loose stools because bile flows continuously into the intestine. It usually improves in a few days.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Can I sleep on my side?', 'Yes, you may sleep on your side if it feels comfortable. Avoid pressure on incision areas.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'When can I resume light exercise?', 'Walking is encouraged immediately. Light exercise can begin in 5–7 days.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'When can I lift weights?', 'Avoid lifting more than 5 kg for 2 weeks to protect the incision.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Is nausea normal?', 'Yes, mild nausea after anesthesia or pain medicines is common and usually settles in 24 hours.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'When can I drive again?', 'You may drive after 5–7 days once your pain is controlled and you can react safely.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Do I need to follow a special diet permanently?', 'No strict long-term diet is needed for most people. However, reducing high-fat foods helps digestion initially.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Why does my stomach feel bloated?', 'Temporary bloating is common due to reduced bowel movement and trapped gas. It improves gradually.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'When will the incision fully heal?', 'Incisions usually heal in 2–3 weeks, but internal healing takes a few months.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Is it normal to feel tired?', 'Yes, tiredness for several days is normal after laparoscopic surgery. Adequate rest helps recovery.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Can I drink coffee or tea?', 'Yes, but start with small amounts if you feel bloated or nauseous.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'Can I take a bath?', 'You may bathe after 48 hours, but keep the incision area dry and avoid rubbing.'),
('87f5bb57-e153-457c-ab02-2c4e03596802', 'When should I contact a doctor?', 'Seek help if you have persistent vomiting, worsening pain, fever, yellowing of eyes, or severe diarrhea.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Is groin tightness normal?', 'Yes, a tight sensation in the groin is common and improves as the muscles heal over 1–2 weeks.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'When can I lift weights again?', 'Avoid lifting anything heavy for at least 4–6 weeks to prevent recurrence.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Why is the area bruised?', 'Bruising is normal after hernia repair due to tissue handling and usually fades within a week.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Can I walk immediately?', 'Yes, gentle walking is encouraged from the same day to improve circulation and reduce stiffness.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Why does the incision itch?', 'Itching indicates healing. Avoid scratching to prevent skin irritation or infection.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'When can I resume driving?', 'Most patients can drive after 7–10 days when they can move comfortably and brake firmly.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Can I sleep on my side?', 'Yes, you may sleep in any comfortable position, but avoid lying directly on the incision area.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Is swelling in the groin normal?', 'Mild swelling is common, especially after standing or walking, and improves with rest and light compression.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Can I resume gym workouts?', 'Light workouts may start after 2 weeks, but avoid heavy lifting until 6 weeks or doctor approval.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'When will I feel fully normal?', 'Most patients feel normal by 4–6 weeks, although mild tightness may last a bit longer.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Why do I feel pulling sensation?', 'A pulling sensation is common as the mesh settles and tissues heal. It improves steadily.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Can I cough or sneeze normally?', 'Yes, but try supporting the incision with your hand to reduce discomfort.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Should I avoid climbing stairs?', 'You may climb stairs slowly as long as you feel stable.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'Is slight numbness around incision normal?', 'Yes, mild numbness happens due to small nerve irritation and usually improves over weeks.'),
('c898a49e-5606-4a68-bdb4-b5825936d5f6', 'When should I worry?', 'Seek help if pain worsens, swelling becomes hard, you develop fever, or the incision leaks fluid.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When can I start walking after C-section?', 'Most mothers can walk slowly within 12–24 hours. Walking helps recovery and reduces blood clot risk.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'Is abdominal pain normal?', 'Yes. Pain and soreness around the incision can last 1–2 weeks and gradually reduce.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When can I start breastfeeding comfortably?', 'You can breastfeed immediately. Use side-lying or football hold to avoid pressure on the incision.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'How long should I avoid lifting heavy weight?', 'Avoid lifting more than your baby’s weight for at least 4–6 weeks.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'Is numbness near the incision normal?', 'Yes. Numbness or tingling happens due to nerve stretching and improves over several weeks.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When can I take a full bath?', 'You may bathe after 48 hours but avoid scrubbing the incision. Ensure the area is fully dry.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'Can I climb stairs after C-section?', 'Yes, slowly and with support. Do not climb repeatedly in the first week.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'How long will bleeding last?', 'Light bleeding or spotting can continue for up to 4–6 weeks, gradually decreasing.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When can I resume driving?', 'You may drive after 2–3 weeks once pain reduces and you can brake comfortably.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'What food should I avoid?', 'Avoid very spicy or heavy foods for the first few days to prevent acidity or constipation.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'Why do I feel tired all the time?', 'Fatigue is common due to surgery, blood loss, and caring for a newborn. Rest and hydration help.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When can I resume normal household work?', 'Light work can be resumed in 2 weeks. Avoid bending, lifting, or sweeping for 4–6 weeks.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'Is constipation normal?', 'Yes, constipation is common after C-section. Increase water, fibre intake, and use stool softeners if advised.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When will stitches heal completely?', 'External healing takes 2 weeks. Internal stitches take around 6–8 weeks to fully heal.'),
('b623b4e3-c003-46f9-9e82-7626b2173e2b', 'When should I contact a doctor?', 'Seek help if there is heavy bleeding, fever, pus from incision, severe pain, or dizziness.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When can I walk without crutches?', 'Most patients start walking without support after 2–3 weeks, depending on physiotherapy progress.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Why is my knee stiff?', 'Knee stiffness is normal and improves with physiotherapy and regular bending exercises.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When can I resume driving?', 'You may drive after 4–6 weeks when you regain knee control and reaction strength.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Is swelling in the knee normal?', 'Mild swelling is common and can last 2–3 weeks. Elevation and ice packs help reduce it.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Can I climb stairs?', 'Yes. Use a railing and go slowly in the first few weeks. Avoid fast or deep bending movements.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When can I return to sports?', 'Light sports may begin after 3 months. Full sports usually resume at 6–9 months with physiotherapy clearance.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Is thigh muscle weakness normal?', 'Yes. Thigh muscles weaken after surgery, and strengthening exercises gradually restore power.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When can I remove the knee brace?', 'Most patients reduce brace use after 2–3 weeks depending on stability and doctor advice.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Why do I feel clicking in my knee?', 'Mild clicking is common during early healing and usually not a concern.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'What exercises help recovery?', 'Quadriceps sets, straight-leg raises, heel slides, and gradual knee bends are essential early exercises.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When can I sit cross-legged?', 'Avoid cross-legged sitting for at least 3 months as it strains the knee joint.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Is numbness around the knee normal?', 'Yes, small nerve branches may be disturbed during surgery and sensation improves gradually.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When will I regain full knee bend?', 'Full bending usually returns over 6–12 weeks with consistent therapy.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'Should I ice my knee daily?', 'Yes. Ice therapy 2–3 times a day helps reduce pain and swelling in the first 2 weeks.'),
('b0177ca1-c9d7-46f5-bec2-95c09b2ed045', 'When should I contact a doctor?', 'Seek help if swelling suddenly increases, you cannot move the knee, or you develop fever or redness.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'When will I start walking?', 'You usually begin walking with support on the same day or next day after surgery.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'Is knee stiffness normal?', 'Yes. Stiffness is common for 4–6 weeks and improves with regular physiotherapy.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'When can I climb stairs?', 'Most patients can climb stairs from day 2–3 with physiotherapy assistance.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'How much swelling is normal?', 'Moderate swelling can last several weeks. Elevating your leg and using ice packs will help.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'When can I sit on the floor?', 'Avoid floor sitting for at least 3 months, as deep bending stresses the new joint.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'Can I resume driving?', 'Driving is usually safe after 4–6 weeks when you can move your leg quickly and safely.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'Is clicking sound normal?', 'Yes, a clicking sound from the artificial joint is common and usually harmless.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'How long will pain last?', 'Pain gradually decreases over 2–4 weeks. Full recovery takes a few months.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'What exercises are essential?', 'Heel slides, knee bends, straight-leg raises, and quadriceps strengthening are key exercises.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'When can I return to office work?', 'Desk work can usually be resumed after 3–4 weeks if walking is comfortable.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'Why does my leg feel heavy?', 'A heavy feeling is common due to swelling and muscle weakness. It improves with exercises.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'Can I use Indian toilets?', 'Avoid squatting toilets, as deep bending is not recommended after knee replacement.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'Is it okay to use stairs daily?', 'Yes, once comfortable, you may use stairs daily—just avoid rushing.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'How long until I feel normal?', 'Most patients feel significantly better by 6–8 weeks, with continued improvement for 6 months.'),
('e5797b86-3c33-420b-9ca3-bf60d54571c7', 'When should I contact a doctor?', 'Seek help if you develop fever, severe pain, sudden swelling, or difficulty moving the joint.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When can I start walking?', 'You will usually begin walking with support on the same day or the next day after surgery.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Can I sleep on my side?', 'Avoid sleeping on the operated side for 4–6 weeks. You may sleep on the opposite side with a pillow between your legs.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When can I climb stairs?', 'You can climb stairs slowly once the physiotherapist confirms it is safe, usually within a couple of days.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Is leg swelling normal?', 'Yes. Mild to moderate swelling is common for several weeks after hip surgery and reduces with elevation.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Why does my hip click when I move?', 'A clicking sound is normal as the artificial hip joint moves. It usually reduces as muscles strengthen.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When can I drive?', 'You may drive after 4–6 weeks once hip movement and reaction time are fully restored.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Can I sit cross-legged?', 'Avoid cross-legged sitting for at least 3 months because it increases the risk of hip dislocation.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Is thigh pain normal?', 'Yes. Mild thigh or groin pain is common and improves as the hip stabilizes.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When will I feel fully stable?', 'Most patients feel stable by 6–8 weeks, with full recovery over several months.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Can I use Indian toilets?', 'Avoid squatting toilets completely, as deep hip bending may cause dislocation.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When can I start physiotherapy?', 'Physiotherapy usually begins within 24 hours and continues for several weeks.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Why do I feel numbness near the incision?', 'Temporary numbness is common due to nerve stretching and improves gradually.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When can I return to office work?', 'Most patients return to desk jobs within 3–4 weeks if mobility is comfortable.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'Can I sit on soft couches?', 'Avoid very low or overly soft chairs. Sit on firm, higher chairs to protect your new hip.'),
('9d1551cc-e8c7-4802-8d31-610cf070374a', 'When should I contact a doctor?', 'Seek help if you develop fever, increasing pain, sudden severe hip pain, or leg numbness.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'When will my vision become clear?', 'Most patients regain clear vision within 1–3 days. Full clarity may take a week.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Can I rub my eye?', 'No. Avoid rubbing or pressing the eye for at least 2 weeks to prevent complications.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'When can I wash my face?', 'You can wash your face after 24 hours but avoid letting water enter the eye.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Is mild redness normal?', 'Yes. Mild redness usually settles within a few days.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'When can I resume reading or mobile use?', 'You can resume mobile or reading activities the next day in moderation.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Do I need to wear sunglasses?', 'Yes. Wearing sunglasses outdoors protects your eyes from dust and bright sunlight.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Can I sleep on my side?', 'Avoid sleeping on the operated side for 1 week.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Is itching normal?', 'Mild itching can occur as the eye heals, but avoid touching or rubbing it.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Can I watch TV?', 'Yes. Watching TV is safe as long as you feel comfortable.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'When can I resume household work?', 'Light tasks can begin in 2–3 days, but avoid heavy lifting for 1 week.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Will I still need glasses?', 'You may need glasses for reading or certain activities depending on your lens type.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Why is my eye watering?', 'Mild watering is common and usually reduces in a few days.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'Can I travel?', 'Short-distance travel is fine after 1–2 days. Avoid dusty environments.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'When can I cook?', 'You may cook after 2–3 days but avoid smoke, heat, and steam directly to the eye.'),
('c57c25f4-703c-4103-8fa8-b63d3ea91d6e', 'When should I seek help?', 'Visit a doctor immediately if you notice sudden vision loss, severe pain, or many floaters.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Why does my throat hurt more at night?', 'Night-time dryness can increase throat pain. Humidifiers and hydration help reduce this.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Is white coating on my throat normal?', 'Yes. A white or yellow coating forms naturally during healing and is not pus.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Can I eat ice cream?', 'Yes! Cold foods like ice cream help reduce pain and swelling.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'When can I eat normal food?', 'Start with soft foods for a few days and gradually return to regular meals as pain improves.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Is ear pain normal?', 'Yes. Ear pain happens due to shared nerves and improves over time.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'How long does bad breath last?', 'Bad breath is common and can last 1–2 weeks until the throat fully heals.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'When can I go to school or work?', 'Most patients resume school/work after 7–10 days, depending on comfort.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Is slight bleeding normal?', 'Small streaks of blood in saliva may occur but heavy bleeding is not normal.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'What drinks should I avoid?', 'Avoid citrus juices and hot drinks as they can irritate the healing throat.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'When can I brush my teeth?', 'You may brush gently from day one but avoid gargling vigorously.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Why does it hurt to yawn?', 'Yawning stretches throat muscles and can cause temporary pain during healing.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Can I exercise?', 'Avoid strenuous exercise for 2 weeks to prevent bleeding risks.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'Is fever normal?', 'A mild fever for the first 1–2 days is normal. High fever is not.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'When will my throat feel better?', 'Most patients feel much better by 7–10 days, with full healing in about 2 weeks.'),
('3d7ae79b-7e31-4352-bf71-116a2dfcd7c4', 'When should I call a doctor?', 'Seek help if there is heavy bleeding, severe dehydration, or fever above 100.4°F.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Why is my voice weak or hoarse?', 'Temporary hoarseness is common due to nerve irritation during surgery. It usually improves in 2–6 weeks.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'When can I take thyroid medicine?', 'Take your thyroid pill every morning on an empty stomach with water. Avoid food for 30 minutes.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Why do my hands or face feel tingling?', 'Tingling can happen due to low calcium levels after thyroid surgery. Inform your doctor if symptoms persist.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Is neck stiffness normal?', 'Yes. Mild stiffness is common and improves with gentle neck movements after a few days.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'When can I resume normal diet?', 'You may eat normal foods once swallowing feels comfortable. Start with soft foods for 1–2 days.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Can I talk normally?', 'Yes, but avoid excessive talking for the first few days to reduce throat strain.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'When can I shower?', 'You may shower after 48 hours but avoid soaking the incision. Gently pat dry.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Is mild neck swelling normal?', 'Yes, mild swelling or bruising is normal and reduces over a week.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'When can I return to work?', 'Most patients return to light work within 1–2 weeks depending on energy and comfort.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Do I need lifelong thyroid medication?', 'If your entire thyroid was removed, lifelong medication is needed. For partial removal, your doctor will decide based on blood tests.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Why does swallowing feel strange?', 'Mild difficulty swallowing is common and improves as swelling decreases.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'When can I exercise?', 'Light walking can start immediately. Avoid strenuous workouts for 2–3 weeks.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'Is scar itching normal?', 'Yes. Itching indicates healing. Avoid scratching the incision.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'How long until the scar improves?', 'The scar fades over several months. Sunscreen and silicone gel help healing.'),
('45285cee-ea8e-4c45-b7d1-3be62d52b9b7', 'When should I contact a doctor?', 'Seek help if you develop severe tingling, muscle cramps, high fever, or increasing neck swelling.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Why is my urine pink or red?', 'Mild blood in urine is normal for 1–2 days after the procedure and should gradually clear.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Why do I feel burning while urinating?', 'Mild burning is common due to irritation of the urinary tract. Drinking more water helps.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'How much water should I drink?', 'Drink 2–3 liters of water daily for the first week unless your doctor advises otherwise.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Is flank pain normal?', 'Mild flank or lower abdomen pain is normal and improves within a few days.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'When can I return to work?', 'Most patients resume normal work in 2–3 days depending on comfort.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Can I drive?', 'You may drive after 24 hours if you feel comfortable and are not taking sedative pain medicines.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Why do I feel pressure in my lower abdomen?', 'Pressure or urgency to urinate is common after the procedure and settles soon.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Is fever normal?', 'A mild fever may occur briefly, but persistent fever is a warning sign and requires medical attention.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Can I exercise?', 'Light walking is fine, but avoid heavy lifting or intense exercise for a week.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'When can I resume sexual activity?', 'Usually after 5–7 days once discomfort settles.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Why is my urine cloudy?', 'Cloudiness can occur as the urinary tract heals. Drink plenty of water to flush it out.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Is stent discomfort normal?', 'If a stent is placed, discomfort or frequent urination is common until it is removed.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'When will the stent be removed?', 'Stents are usually removed within 1–2 weeks unless your doctor suggests otherwise.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'Why do I feel tired?', 'Fatigue is normal for 1–2 days after anesthesia. It improves with rest and hydration.'),
('b6b48a21-b484-40f6-a3de-c69aba7b6512', 'When should I contact a doctor?', 'Seek help immediately if you develop severe flank pain, high fever, heavy bleeding, or inability to urinate.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Why is bowel movement painful?', 'Pain during bowel movement is expected for a few days. Warm sitz baths and stool softeners help reduce discomfort.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'How long will bleeding continue?', 'Light bleeding or spotting may occur for 1–2 weeks and gradually reduces.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'What food should I avoid?', 'Avoid spicy foods and reduce caffeine to prevent irritation and constipation.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'How much water should I drink?', 'Drink at least 2–3 liters of water daily to soften stools and reduce strain.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Is swelling normal?', 'Yes, swelling around the anus is normal after surgery and improves gradually.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'When can I sit comfortably?', 'You may sit normally after a few days but a soft cushion helps reduce pressure.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Why does it itch?', 'Itching occurs as the wound heals. Keep the area clean and dry, and avoid scratching.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Can I walk?', 'Yes. Walking is encouraged immediately and helps recovery.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'When can I resume work?', 'Most people return to office work in 5–7 days depending on pain levels.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Why does sitting hurt?', 'Post-surgery inflammation can make sitting uncomfortable. Use a donut cushion for relief.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Can I exercise?', 'Avoid heavy exercise for 2 weeks. Light walking is recommended.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Is mucus discharge normal?', 'Yes. Small amounts of mucus discharge are common for 1–2 weeks.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'Do I need a high-fiber diet?', 'Yes. High-fiber foods help prevent constipation and promote healing.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'How to care for the wound?', 'Take sitz baths, keep the area clean, avoid rubbing, and use prescribed ointments.'),
('4a87d21c-6bb6-41d3-935f-4c64a58e539a', 'When should I contact a doctor?', 'Seek help if you have heavy bleeding, severe pain, fever, or inability to pass stool.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Why is my breast swollen?', 'Swelling is normal after lumpectomy and may take 1–2 weeks to settle. Cold packs may help.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'When can I remove the dressing?', 'Dressings are usually removed after 48 hours unless advised otherwise.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Can I sleep on my operated side?', 'Avoid sleeping on the operated side for 1–2 weeks to reduce pain and pressure.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Is mild breast pain normal?', 'Yes. Mild pain or discomfort is normal and improves gradually over several days.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'When can I take a shower?', 'You may shower after 48 hours but avoid direct water pressure on the incision.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Is bruising normal?', 'Yes. Bruising around the breast is common after surgery and fades within a week.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'When can I return to work?', 'Most patients return to office work within 3–5 days depending on comfort.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Why do I feel a lump after surgery?', 'A firm lump or hardness at the surgery site is common and gradually softens over a few weeks.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Can I exercise?', 'Walking is fine immediately. Avoid upper body workouts for 2 weeks.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'When can I wear a bra again?', 'A soft support bra can be worn immediately to reduce discomfort and swelling.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Is nipple sensitivity normal?', 'Yes. Temporary changes in nipple sensitivity may occur and improve gradually.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'How long until the scar fades?', 'Scars improve significantly over 2–3 months and may continue fading for a year.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Can I lift my arm normally?', 'Gentle arm movement is encouraged, but avoid overhead lifting for 1–2 weeks.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'Why do I feel tired?', 'Fatigue is common after breast surgery and improves with rest and hydration.'),
('3d9eeae5-9e57-4da3-bd5d-b9be4a126fa5', 'When should I contact a doctor?', 'Seek help if the incision becomes red, painful, or drains pus, or if fever develops.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'Is abdominal pain normal?', 'Mild abdominal discomfort is expected for 1–2 weeks and gradually improves.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'How long will vaginal discharge last?', 'Light discharge may continue for 2–4 weeks and gradually reduces.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'Can I climb stairs?', 'Yes, climb slowly and avoid multiple trips in the first week.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'Is back pain normal?', 'Yes. Back pain can occur due to posture changes and healing, and usually improves in a few days.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'When can I walk normally?', 'Walking is encouraged from day one and helps recovery.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'When can I take a bath?', 'You may take a bath after 48 hours, but avoid soaking in a tub for 2 weeks.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'What foods should I avoid?', 'Avoid very spicy or greasy foods early on to prevent acidity or constipation.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'Why do I feel tired?', 'Fatigue is common after hysterectomy due to hormonal adjustments and healing.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'When can I resume work?', 'Desk work can usually be resumed in 3–4 weeks depending on recovery.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'When can I return to exercise?', 'Light walking is fine. Avoid heavy workouts for 4–6 weeks.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'Why is my stomach bloated?', 'Bloating is common due to slow bowel movement after surgery and improves with time.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'Why does my incision itch?', 'Itching is a sign of healing. Avoid scratching the incision to prevent infection.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'How long until full recovery?', 'Full recovery takes around 6–8 weeks depending on activity level and overall health.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'When can I drive?', 'Driving is usually safe after 3–4 weeks once pain reduces and movement is comfortable.'),
('87ff13a6-0372-4b6f-bf09-633abfd1ba69', 'When should I contact a doctor?', 'Seek help if bleeding increases, pain worsens, fever develops, or there is foul-smelling discharge.');
INSERT INTO core.surgery_faqs (master_surgery_id, question, answer) VALUES
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Why do I feel pain during bowel movement?', 'Mild pain is common for a few days. Sitz baths and stool softeners help ease discomfort.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'How long will bleeding continue?', 'Small streaks of blood may appear for 2–3 days but should reduce gradually.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'What foods should I eat?', 'Eat high-fiber foods like fruits, vegetables, and whole grains to prevent constipation.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Can I sit normally?', 'Yes, but using a soft cushion can help reduce pressure and pain.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Why does it itch?', 'Itching is due to healing. Keep the area clean and avoid scratching.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'When can I return to work?', 'Most patients return to office work in 3–5 days depending on comfort.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Can I exercise?', 'Light walking is okay. Avoid heavy exercise for 1–2 weeks.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Is mucus discharge normal?', 'Yes. A small amount of mucus discharge is common for a few days.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'How often should I take sitz baths?', 'Warm sitz baths 2–3 times a day help with healing and pain relief.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Is swelling normal?', 'Yes. Mild swelling reduces gradually as the area heals.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'When can I drive?', 'Driving is safe after 3–5 days once sitting is comfortable.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Can I climb stairs?', 'Yes. Climbing stairs is usually fine unless pain increases.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'Why do I feel a stretching sensation?', 'A stretching or pulling sensation is common as the wound heals.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'How long until full recovery?', 'Most patients feel much better within 1–2 weeks with proper care.'),
('d5095df1-2dba-48db-8737-4ff9c71b03ee', 'When should I contact a doctor?', 'Seek help if you have severe pain, fever, heavy bleeding, or inability to pass stool.');
